import { useEffect, useState, useCallback } from 'react'

import {
  CheckCircle as CheckCircleIcon,
  FitnessCenter as FitnessCenterIcon,
} from '@mui/icons-material'
import {
  Box,
  Chip,
  CircularProgress,
  Container,
  Divider,
  LinearProgress,
  Paper,
  Typography,
} from '@mui/material'

import { getCompletedUnitsByPlanIds, getTodaysExecutionsByPlanIds } from '@/api/trainingExecutions'
import { getTrainingPlans } from '@/api/trainingPlans'
import { LoginButton } from '@/components/LoginButton'
import { PlanExecutionButton } from '@/components/PlanExecutionButton'
import { useAuth } from '@/contexts/AuthContext'
import type { TrainingPlan } from '@/types/database'
import { toLocalDateKey, parseDateKey } from '@/utils/date'
import {
  calculateEndDateFromCompletedUnits,
  formatDate,
  getTodaysPlans,
  getWeekDayLabel,
} from '@/utils/schedule'
import { renderUnit } from '@/utils/unit-utils'

interface StoredEndDate {
  savedAt: string // YYYY-MM-DD - day of last snapshot
  endDate: string // YYYY-MM-DD - end date at that snapshot (becomes next day's baseline)
  baseline?: string // YYYY-MM-DD - baseline for today's delta (previous day's snapshot)
}

function storageKey(planId: number): string {
  return `tb_endDate_${planId}`
}

function loadStoredEndDate(planId: number): StoredEndDate | null {
  try {
    const raw = localStorage.getItem(storageKey(planId))
    return raw ? (JSON.parse(raw) as StoredEndDate) : null
  } catch {
    return null
  }
}

function saveStoredEndDate(planId: number, value: StoredEndDate): void {
  localStorage.setItem(storageKey(planId), JSON.stringify(value))
}

function deltaFromBaseline(baseline: string, newEndDate: Date): number {
  const prev = parseDateKey(baseline)
  return Math.round((newEndDate.getTime() - prev.getTime()) / 86_400_000)
}

export function HomePage() {
  const { user } = useAuth()
  const [todaysPlans, setTodaysPlans] = useState<TrainingPlan[]>([])
  const [todayExecutionMap, setTodayExecutionMap] = useState<Map<number, number>>(new Map())
  const [endDateMap, setEndDateMap] = useState<Map<number, Date>>(new Map())
  const [endDateDeltaMap, setEndDateDeltaMap] = useState<Map<number, number>>(new Map())
  const [loading, setLoading] = useState(false)

  const loadTodaysPlans = useCallback(async () => {
    try {
      setLoading(true)
      const userId = user?.id
      const plans = await getTrainingPlans(userId)
      const filtered = getTodaysPlans(plans)
      setTodaysPlans(filtered)

      if (filtered.length > 0) {
        const planIds = filtered.map((p) => p.id)
        const [executions, completedUnits] = await Promise.all([
          getTodaysExecutionsByPlanIds(planIds, userId),
          getCompletedUnitsByPlanIds(planIds, userId),
        ])

        const todayMap = new Map<number, number>()
        for (const exec of executions) {
          todayMap.set(exec.plan_id, (todayMap.get(exec.plan_id) ?? 0) + exec.unit_count)
        }
        setTodayExecutionMap(todayMap)

        const newEndDateMap = new Map<number, Date>()
        const deltaMap = new Map<number, number>()
        const today = toLocalDateKey(new Date())

        for (const plan of filtered) {
          const units = completedUnits.get(plan.id) ?? 0
          const endDate = calculateEndDateFromCompletedUnits(plan, units)
          newEndDateMap.set(plan.id, endDate)

          const stored = loadStoredEndDate(plan.id)
          const newEndKey = toLocalDateKey(endDate)
          let baseline: string | undefined

          if (!stored) {
            saveStoredEndDate(plan.id, { savedAt: today, endDate: newEndKey })
          } else if (stored.savedAt === today) {
            baseline = stored.baseline
          } else {
            baseline = stored.endDate
            saveStoredEndDate(plan.id, { savedAt: today, endDate: newEndKey, baseline })
          }

          if (baseline) {
            const delta = deltaFromBaseline(baseline, endDate)
            if (delta !== 0) deltaMap.set(plan.id, delta)
          }
        }

        setEndDateMap(newEndDateMap)
        setEndDateDeltaMap(deltaMap)
      } else {
        setTodayExecutionMap(new Map())
        setEndDateMap(new Map())
        setEndDateDeltaMap(new Map())
      }
    } catch {
      // Silently fail
    } finally {
      setLoading(false)
    }
  }, [user?.id])

  useEffect(() => {
    if (user) {
      loadTodaysPlans()
    }
  }, [user, loadTodaysPlans])

  const today = new Date()
  const dateStr = today.toLocaleDateString('ko-KR', { month: 'long', day: 'numeric' })
  const weekdayStr = today.toLocaleDateString('ko-KR', { weekday: 'long' })

  const sortedPlans = [...todaysPlans].sort((a, b) => {
    const aAchieved = (todayExecutionMap.get(a.id) ?? 0) >= a.unit_amount ? 1 : 0
    const bAchieved = (todayExecutionMap.get(b.id) ?? 0) >= b.unit_amount ? 1 : 0
    return aAchieved - bAchieved
  })

  if (!user) {
    return (
      <Container maxWidth="sm">
        <Box sx={{ my: 4, textAlign: 'center' }}>
          <Paper elevation={3} sx={{ p: 3 }}>
            <Typography variant="body1" sx={{ mb: 3 }}>
              시작하려면 로그인하세요
            </Typography>
            <LoginButton />
          </Paper>
        </Box>
      </Container>
    )
  }

  return (
    <Box sx={{ bgcolor: 'background.default', minHeight: '100%', pb: 2 }}>
      {/* Date header */}
      <Box sx={{ px: 2, pt: 2, pb: 1.5 }}>
        <Typography variant="caption" color="text.secondary" display="block">
          {weekdayStr}, {dateStr}
        </Typography>
        <Typography variant="h6" fontWeight="bold" lineHeight={1.2}>
          오늘의 훈련
        </Typography>
      </Box>

      {/* Plan list card — edge-to-edge on mobile */}
      <Paper elevation={0} sx={{ mx: { xs: 0, sm: 2 }, borderRadius: { xs: 0, sm: 2 } }}>
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
            <CircularProgress size={24} />
          </Box>
        ) : sortedPlans.length === 0 ? (
          <Box sx={{ py: 5, textAlign: 'center' }}>
            <Typography color="text.secondary">오늘 예정된 훈련이 없습니다</Typography>
          </Box>
        ) : (
          sortedPlans.map((plan, index) => {
            const todayUnits = todayExecutionMap.get(plan.id) ?? 0
            const isAchieved = todayUnits >= plan.unit_amount
            const progress = Math.min(100, (todayUnits / plan.unit_amount) * 100)
            const scheduleLabel =
              plan.schedule_type === 'daily'
                ? '매일'
                : plan.schedule_days?.map(getWeekDayLabel).join(', ')
            const endDate = endDateMap.get(plan.id)
            const delta = endDateDeltaMap.get(plan.id)

            return (
              <Box key={plan.id}>
                {index > 0 && <Divider />}
                <Box
                  sx={{
                    px: 2,
                    pt: 1.5,
                    pb: todayUnits > 0 ? 1 : 1.5,
                    bgcolor: isAchieved ? 'action.hover' : 'background.paper',
                  }}
                >
                  {/* Main row: icon · name+meta · button */}
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
                    {isAchieved ? (
                      <CheckCircleIcon color="success" fontSize="small" sx={{ flexShrink: 0 }} />
                    ) : (
                      <FitnessCenterIcon color="primary" fontSize="small" sx={{ flexShrink: 0 }} />
                    )}

                    <Box sx={{ flex: 1, minWidth: 0 }}>
                      <Typography
                        variant="body1"
                        fontWeight={500}
                        color={isAchieved ? 'text.secondary' : 'text.primary'}
                        noWrap
                      >
                        {plan.name}
                      </Typography>
                      <Box
                        sx={{
                          display: 'flex',
                          alignItems: 'center',
                          gap: 0.75,
                          mt: 0.25,
                          flexWrap: 'wrap',
                        }}
                      >
                        <Typography variant="caption" color="text.secondary">
                          {plan.unit_amount} {renderUnit(plan.unit_name)}
                        </Typography>
                        <Chip
                          label={scheduleLabel}
                          size="small"
                          variant="outlined"
                          sx={{ height: 16, fontSize: '0.6rem', '& .MuiChip-label': { px: 0.75 } }}
                        />
                        {endDate && (
                          <Typography variant="caption" color="text.secondary" noWrap>
                            ~{formatDate(endDate)}
                            {delta !== undefined && (
                              <Box
                                component="span"
                                sx={{
                                  color: delta < 0 ? 'success.main' : 'error.main',
                                  ml: 0.5,
                                }}
                              >
                                ({delta > 0 ? '+' : ''}
                                {delta}일)
                              </Box>
                            )}
                          </Typography>
                        )}
                      </Box>
                    </Box>

                    <PlanExecutionButton
                      plan={plan}
                      size="small"
                      variant={isAchieved ? 'outlined' : 'contained'}
                    />
                  </Box>

                  {/* Progress bar */}
                  {todayUnits > 0 && (
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 1 }}>
                      <LinearProgress
                        variant="determinate"
                        value={progress}
                        color={isAchieved ? 'success' : 'primary'}
                        sx={{ flex: 1, borderRadius: 1, height: 5 }}
                      />
                      <Typography
                        variant="caption"
                        color={isAchieved ? 'success.main' : 'text.secondary'}
                        sx={{ whiteSpace: 'nowrap' }}
                      >
                        {isAchieved
                          ? `${todayUnits} 달성 ✓`
                          : `${todayUnits} / ${plan.unit_amount}`}
                      </Typography>
                    </Box>
                  )}
                </Box>
              </Box>
            )
          })
        )}
      </Paper>
    </Box>
  )
}
